from datetime import datetime

def is_expired(pasta_date):
    now = datetime.now()
    delta = now - datetime.strptime(pasta_date, '%A %b %d %Y')
    return delta.days > 2

date = input("What date did you see the pasta? ")
if is_expired(date):
    print("Don't eat that!")
